/**
 * Retrieves sales rows by date range using parameterized SQL.
 *
 * @fromDate Inclusive start date.
 * @toDate Inclusive end date.
 * @return query
 */
public query function getSalesByRange(required date fromDate, required date toDate) {
  return queryExecute(
    'SELECT orderId, customerId, totalAmount FROM orders WHERE createdAt >= :fromDate AND createdAt <= :toDate',
    {
      fromDate: { value: arguments.fromDate, cfsqltype: 'cf_sql_timestamp' },
      toDate: { value: arguments.toDate, cfsqltype: 'cf_sql_timestamp' }
    },
    { datasource: variables.datasource }
  );
}

/**
 * Returns users with aggregated order totals using a single query.
 *
 * @customerIds Customer identifiers.
 * @return query
 */
public query function getUserOrderSummary(required array customerIds) {
  return queryExecute(
    'SELECT u.id, u.email, COALESCE(SUM(o.totalAmount), 0) AS totalSpent FROM users u LEFT JOIN orders o ON o.customerId = u.id WHERE u.id IN (:customerIds) GROUP BY u.id, u.email',
    { customerIds: { value: arguments.customerIds, cfsqltype: 'cf_sql_integer', list: true } },
    { datasource: variables.datasource }
  );
}

/**
 * Returns normalized customer summary as struct for service layer consumption.
 *
 * @customerId Customer identifier.
 * @return struct
 */
public struct function getCustomerSummary(required numeric customerId) {
  var rows = queryExecute(
    'SELECT id, email, status FROM users WHERE id = :customerId',
    { customerId: { value: arguments.customerId, cfsqltype: 'cf_sql_integer' } },
    { datasource: variables.datasource }
  );

  if (!rows.recordCount) {
    return { found: false };
  }

  return { found: true, id: rows.id[1], email: rows.email[1], status: rows.status[1] };
}

