/**
 * Retrieves paged report rows with database-side filtering and ordering.
 *
 * @status Status filter.
 * @offset Row offset.
 * @pageSize Row count.
 * @return query
 */
public query function getPagedReportRows(required string status, required numeric offset, required numeric pageSize) {
  return queryExecute(
    'SELECT id, title, status, createdAt FROM report_items WHERE status = :status ORDER BY createdAt DESC LIMIT :pageSize OFFSET :offset',
    {
      status: { value: arguments.status, cfsqltype: 'cf_sql_varchar' },
      pageSize: { value: arguments.pageSize, cfsqltype: 'cf_sql_integer' },
      offset: { value: arguments.offset, cfsqltype: 'cf_sql_integer' }
    },
    { datasource: variables.datasource }
  );
}

/**
 * Inserts a new user and returns the generated identifier.
 *
 * @email string         User email address.
 * @displayName string   User display name.
 * @return numeric
 */
public numeric function insertUser(required string email, required string displayName) {
  queryExecute(
    'INSERT INTO users (email, displayName, createdAt) VALUES (:email, :displayName, :now)',
    {
      email: { value: arguments.email, cfsqltype: 'cf_sql_varchar' },
      displayName: { value: arguments.displayName, cfsqltype: 'cf_sql_varchar' },
      now: { value: now(), cfsqltype: 'cf_sql_timestamp' }
    },
    { datasource: variables.datasource, result: 'insertResult' }
  );
  return insertResult.generatedKey;
}

