/**
 * Returns a paged list of users ordered by creation date.
 *
 * @page numeric     1-based page number.
 * @perPage numeric  Records per page.
 * @return query
 */
public query function getPaged(required numeric page, numeric perPage = 25) {
  var offset = (arguments.page - 1) * arguments.perPage;
  return queryExecute(
    'SELECT id, email, displayName, createdAt FROM users WHERE isDeleted = 0 ORDER BY createdAt DESC LIMIT :perPage OFFSET :offset',
    {
      perPage: { value: arguments.perPage, cfsqltype: 'cf_sql_integer' },
      offset: { value: offset, cfsqltype: 'cf_sql_integer' }
    },
    { datasource: variables.datasource }
  );
}

