/**
 * Returns true when the given email is already registered.
 *
 * @email string   Email address to check.
 * @return boolean
 */
public boolean function emailExists(required string email) {
  var result = queryExecute(
    'SELECT COUNT(*) AS cnt FROM users WHERE email = :email AND isDeleted = 0',
    { email: { value: arguments.email, cfsqltype: 'cf_sql_varchar' } },
    { datasource: variables.datasource }
  );
  return result.cnt > 0;
}

/**
 * Returns the total number of users for a given status.
 *
 * @status string   Status filter value.
 * @return numeric
 */
public numeric function countByStatus(required string status) {
  var result = queryExecute(
    'SELECT COUNT(*) AS total FROM users WHERE status = :status AND isDeleted = 0',
    { status: { value: arguments.status, cfsqltype: 'cf_sql_varchar' } },
    { datasource: variables.datasource }
  );
  return result.total;
}

/**
 * Returns a user by ID, or null when the record does not exist.
 *
 * @userId numeric   User identifier.
 * @return struct
 */
public any function findById(required numeric userId) {
  var qry = queryExecute(
    'SELECT id, email, displayName, status FROM users WHERE id = :userId AND isDeleted = 0',
    { userId: { value: arguments.userId, cfsqltype: 'cf_sql_integer' } },
    { datasource: variables.datasource }
  );
  if (!qry.recordCount) {
    return javaCast('null', '');
  }
  return { id: qry.id, email: qry.email, displayName: qry.displayName, status: qry.status };
}

