/**
 * Returns a static status-code lookup as a query object using CF2025
 * QueryNew() inline data syntax — no database round-trip needed.
 *
 * @return query  Columns: code (integer), name (varchar), label (varchar).
 */
public query function getStatusCodes() {
    // CF2025+: QueryNew() accepts column names, types, and initial row data in one call
    return QueryNew(
        "code, name, label",
        "integer, varchar, varchar",
        [
            [1, "active",    "Active"],
            [2, "inactive",  "Inactive"],
            [3, "suspended", "Suspended"],
            [4, "pending",   "Pending Review"]
        ]
    );
}

fallbackPattern:
// CF10-safe fallback: QueryNew() + QueryAddRow() pattern
public query function getStatusCodes() {
    var q = QueryNew('code,name,label', 'integer,varchar,varchar');
    var rows = [
        { code: 1, name: 'active',    label: 'Active' },
        { code: 2, name: 'inactive',  label: 'Inactive' },
        { code: 3, name: 'suspended', label: 'Suspended' },
        { code: 4, name: 'pending',   label: 'Pending Review' }
    ];
    for (var row in rows) {
        QueryAddRow(q);
        q.code[q.recordCount]  = row.code;
        q.name[q.recordCount]  = row.name;
        q.label[q.recordCount] = row.label;
    }
    return q;
}
